# --------- ОЖИДАЕМ, ЧТО ГДЕ-ТО ВЫШЕ/РЯДОМ ОПРЕДЕЛЁН DATA ---------
# DATA = [...]  # список словарей с ключами: "кто","тип","здоровье","инит","броня","точн","точн2","урон","урон2",
#                                        "иммунитет","защита","тип атаки1","тип атаки2","размер"
# ------------------------------------------------------------------

# ===================== НОРМАЛИЗАЦИЯ/КАНОНИЗАЦИЯ ====================
_ATK_CANON = {
    "weapon": "Weapon",
    "earth": "Earth",
    "fire": "Fire",
    "water": "Water",
    "poison": "Poison",
    "death": "Death",
    "mind": "Mind",
    "life": "Life",
    "air": "Air",
    "": ""
}
def _canon_attack(x: str) -> str:
    return _ATK_CANON.get((x or "").lower(), (x or ""))

def _canon_list(xs):
    return [_ATK_CANON.get((x or "").lower(), (x or "")) for x in (xs or [])]


def _unit_type(u: dict) -> str:
    # Pass unit type through unchanged; _TYPE_CANON is unused here
    val = u.get("тип", "")
    return "" if val is None else str(val)

def _stand(u: dict) -> str:
    # ближник (weapon) или большой — впереди, иначе — позади
    if (u.get("тип атаки1", "").lower() == "weapon") or bool(u.get("размер", 0)):
        return "ahead"
    return "behind"

def _armor(u: dict) -> int:
    try:
        return int(round(float(u.get("броня", 0)) * 100))
    except Exception:
        return 0

def _to_acc(v) -> int:
    try:
        return int(round(float(v) * 100))
    except Exception:
        return 0

def _get(u: dict, *keys, default=0):
    for k in keys:
        if k in u:
            return u[k]
    return default

def map_unit_to_battle(u: dict, team: str, position: int) -> dict:
    """Маппинг одного словаря из DATA -> объект боевого юнита с ключами целевого формата."""
    initv = int(_get(u, "инит", "инициатива", default=0))
    hp = int(_get(u, "здоровье", "hp", default=0))
    return {
        "name": u.get("кто", ""),
        "initiative": initv,
        "initiative_base": initv,
        "team": team,
        "position": position,
        "stand": _stand(u),
        "unit_type": _unit_type(u),

        "damage": int(_get(u, "урон", "damage", default=0)),
        "damage_secondary": int(_get(u, "урон2", "damage2", default=0)),

        "health": hp,
        "max_health": hp,
        "armor": _armor(u),

        "accuracy": _to_acc(_get(u, "точн", "accuracy", default=0)),
        "accuracy_secondary": _to_acc(_get(u, "точн2", "accuracy2", default=0)),

        "immunity": _canon_list(u.get("иммунитет", [])),
        "resistance": _canon_list(u.get("защита", [])),
        "attack_type_primary": _canon_attack(u.get("тип атаки1", "")),
        "attack_type_secondary": _canon_attack(u.get("тип атаки2", "")),

        "big": bool(u.get("размер", 0)),
        "paralyzed": 0,
        "long_paralyzed": 0,
        "running_away": 0,
        "transformed": 0,
        "basestats": [],
    }

# =========================== ПЛЕЙСХОЛДЕРЫ ==========================
NO_SELECTION = "— пусто —"

def default_stand_for_position(position: int) -> str:
    # 1..3 и 7..9 — передняя линия, 4..6 и 10..12 — задняя
    if position in (1, 2, 3, 7, 8, 9):
        return "ahead"
    return "behind"

def placeholder_unit(team: str, position: int) -> dict:
    return {
        "name": "пусто",
        "initiative": 0,
        "initiative_base": 0,
        "team": team,
        "position": position,
        "stand": default_stand_for_position(position),
        "unit_type": "Archer",
        "damage": 0,
        "damage_secondary": 0,
        "health": 0,
        "max_health": 0,
        "armor": 0,
        "accuracy": 0,
        "accuracy_secondary": 0,
        "immunity": [],
        "resistance": [],
        "attack_type_primary": "Weapon",
        "attack_type_secondary": "",
        "big": False,
        "paralyzed": 0,
        "long_paralyzed": 0,
        "running_away": 0,
        "transformed": 0,
        "basestats": [],
    }

# ========================= ВСПОМОГАТЕЛЬНОЕ =========================
def build_name_index(data_list):
    """Собираем индекс имя -> список юнитов (на случай совпадений имен)."""
    idx = {}
    for u in data_list:
        name = u.get("кто", "")
        idx.setdefault(name, []).append(u)
    return idx

def first_by_name(name, name_index):
    lst = name_index.get(name, [])
    return lst[0] if lst else None

# --- запись в файл 1workingbattle.py ---
BEGIN_MARK = "# === BEGIN CUSTOM UNITS (GUI) ==="
END_MARK   = "# === END CUSTOM UNITS (GUI) ==="

def _render_units_block(units_red, units_blue) -> str:
    ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    block = [
        "",
        BEGIN_MARK,
        f"# Generated at {ts}",
        f"UNITS_RED = {pformat(units_red, width=120, compact=False, sort_dicts=False)}",
        "",
        f"UNITS_BLUE = {pformat(units_blue, width=120, compact=False, sort_dicts=False)}",
        END_MARK,
        "",
    ]
    return "\n".join(block)

def write_units_to_file(py_path: str, units_red, units_blue) -> None:
    content = ""
    if os.path.exists(py_path):
        with open(py_path, "r", encoding="utf-8") as f:
            content = f.read()

    # вырежем предыдущий кастомный блок, если есть
    if BEGIN_MARK in content and END_MARK in content:
        content = re.sub(
            re.escape(BEGIN_MARK) + r".*?" + re.escape(END_MARK),
            BEGIN_MARK + "\n" + END_MARK,
            content,
            flags=re.DOTALL
        )

    new_block = _render_units_block(units_red, units_blue)
    if content:
        if not content.endswith("\n"):
            content += "\n"
        content += new_block
    else:
        content = new_block.lstrip("\n")

    with open(py_path, "w", encoding="utf-8") as f:
        f.write(content)

# --- запуск боя ---
def run_battle(py_path: str):
    try:
        subprocess.Popen([sys.executable, py_path])
    except Exception as e:
        messagebox.showerror("Ошибка запуска", f"Не удалось запустить {py_path}\n{e}")

# ============================= GUI ===============================
class BattleSelectorGUI:
    def __init__(self, master, data_list):
        self.master = master
        self.data_list = data_list
        self.name_index = build_name_index(data_list)

        master.title("Red vs Blue — выбор юнитов (передняя/задняя линии)")
        master.grid_columnconfigure(0, weight=1)
        master.grid_columnconfigure(1, weight=0)
        master.grid_columnconfigure(2, weight=1)

        # --- общий список имён: любой юнит доступен в любом селекторе ---
        # Сохраняем порядок из исходного DATA (без сортировки)
        self.names_all = [NO_SELECTION] + list(self.name_index.keys())

        # Заголовки
        Label(master, text="RED").grid(row=0, column=0, pady=(10, 5))
        Label(master, text=" ").grid(row=0, column=1)
        Label(master, text="BLUE").grid(row=0, column=2, pady=(10, 5))

        Label(master, text="Передняя линия (pos 1–3)").grid(row=1, column=0, pady=(0, 4))
        Label(master, text=" ").grid(row=1, column=1)
        Label(master, text="Передняя линия (pos 7–9)").grid(row=1, column=2, pady=(0, 4))

        # --- VARs и комбобоксы: передняя линия ---
        self.red_ahead_vars = [StringVar(value=NO_SELECTION) for _ in range(3)]
        self.blue_ahead_vars = [StringVar(value=NO_SELECTION) for _ in range(3)]
        self.red_ahead_boxes = []
        self.blue_ahead_boxes = []

        for i in range(3):
            cb = Combobox(master, textvariable=self.red_ahead_vars[i],
                          values=self.names_all, width=36, state="readonly")
            cb.grid(row=2+i, column=0, padx=10, pady=3, sticky=E+W)
            self.red_ahead_boxes.append(cb)

            cb2 = Combobox(master, textvariable=self.blue_ahead_vars[i],
                           values=self.names_all, width=36, state="readonly")
            cb2.grid(row=2+i, column=2, padx=10, pady=3, sticky=E+W)
            self.blue_ahead_boxes.append(cb2)

        Label(master, text="Задняя линия (pos 4–6)").grid(row=5, column=0, pady=(8, 4))
        Label(master, text=" ").grid(row=5, column=1)
        Label(master, text="Задняя линия (pos 10–12)").grid(row=5, column=2, pady=(8, 4))

        # --- VARs и комбобоксы: задняя линия ---
        self.red_behind_vars = [StringVar(value=NO_SELECTION) for _ in range(3)]
        self.blue_behind_vars = [StringVar(value=NO_SELECTION) for _ in range(3)]
        self.red_behind_boxes = []
        self.blue_behind_boxes = []

        for i in range(3):
            cb = Combobox(master, textvariable=self.red_behind_vars[i],
                          values=self.names_all, width=36, state="readonly")
            cb.grid(row=6+i, column=0, padx=10, pady=3, sticky=E+W)
            self.red_behind_boxes.append(cb)

            cb2 = Combobox(master, textvariable=self.blue_behind_vars[i],
                           values=self.names_all, width=36, state="readonly")
            cb2.grid(row=6+i, column=2, padx=10, pady=3, sticky=E+W)
            self.blue_behind_boxes.append(cb2)

        # Кнопки управления
        btn_frame = Frame(master)
        btn_frame.grid(row=9, column=0, columnspan=3, pady=(12, 10))
        Button(btn_frame, text="Очистить", command=self.clear_all).grid(row=0, column=0, padx=5)
        Button(btn_frame, text="Предпросмотр JSON", command=self.preview).grid(row=0, column=1, padx=5)
        Button(btn_frame, text="Записать в 1workingbattle.py", command=self.save_to_file).grid(row=0, column=2, padx=5)
        Button(btn_frame, text="Записать и запустить бой", command=self.save_and_run).grid(row=0, column=3, padx=5)

        # удобный список для очистки
        self._all_vars = (
            self.red_ahead_vars + self.red_behind_vars +
            self.blue_ahead_vars + self.blue_behind_vars
        )

    # --- вспомогательное чтение выбранного имени -> юнит ---
    def _u_by_name(self, name):
        if not name or name == NO_SELECTION:
            return None
        return first_by_name(name, self.name_index)

    # --- сбор и маппинг выбранных юнитов (БЕЗ плейсхолдеров) ---
    def _collect_units_compact(self):
        red_positions = {}
        blue_positions = {}

        # RED передняя 1..3 — позиция = индекс селектора (без сжатия)
        for idx, v in enumerate(self.red_ahead_vars):
            name = v.get()
            pos = 1 + idx
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    red_positions[pos] = map_unit_to_battle(u, "red", pos)

        # RED задняя 4..6 — позиция = индекс селектора
        for idx, v in enumerate(self.red_behind_vars):
            name = v.get()
            pos = 4 + idx
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    red_positions[pos] = map_unit_to_battle(u, "red", pos)

        # BLUE передняя 7..9
        for idx, v in enumerate(self.blue_ahead_vars):
            name = v.get()
            pos = 7 + idx
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    blue_positions[pos] = map_unit_to_battle(u, "blue", pos)

        # BLUE задняя 10..12
        for idx, v in enumerate(self.blue_behind_vars):
            name = v.get()
            pos = 10 + idx
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    blue_positions[pos] = map_unit_to_battle(u, "blue", pos)

        if (not red_positions) or (not blue_positions):
            messagebox.showwarning("Недостаточно юнитов", "Нужно выбрать минимум по одному юниту на каждую сторону.")
            return None, None

        units_red = [red_positions[p] for p in range(1, 7) if p in red_positions]
        units_blue = [blue_positions[p] for p in range(7, 13) if p in blue_positions]
        return units_red, units_blue

    # --- сбор для предпросмотра (С плейсхолдерами "пусто") ---
    def _collect_units_with_placeholders(self):
        red_positions = {i: None for i in range(1, 7)}
        blue_positions = {i: None for i in range(7, 13)}

        # RED передняя 1..3
        for idx, v in enumerate(self.red_ahead_vars):
            pos = 1 + idx
            name = v.get()
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    red_positions[pos] = map_unit_to_battle(u, "red", pos)
        # RED задняя 4..6
        for idx, v in enumerate(self.red_behind_vars):
            pos = 4 + idx
            name = v.get()
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    red_positions[pos] = map_unit_to_battle(u, "red", pos)

        # BLUE передняя 7..9
        for idx, v in enumerate(self.blue_ahead_vars):
            pos = 7 + idx
            name = v.get()
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    blue_positions[pos] = map_unit_to_battle(u, "blue", pos)
        # BLUE задняя 10..12
        for idx, v in enumerate(self.blue_behind_vars):
            pos = 10 + idx
            name = v.get()
            if name != NO_SELECTION:
                u = self._u_by_name(name)
                if u:
                    blue_positions[pos] = map_unit_to_battle(u, "blue", pos)

        any_red = any(red_positions[p] is not None for p in red_positions)
        any_blue = any(blue_positions[p] is not None for p in blue_positions)
        if not any_red or not any_blue:
            messagebox.showwarning("Недостаточно юнитов", "Нужно выбрать минимум по одному юниту на каждую сторону.")
            return None, None

        units_red = [red_positions[p] if red_positions[p] is not None else placeholder_unit("red", p)
                     for p in range(1, 7)]
        units_blue = [blue_positions[p] if blue_positions[p] is not None else placeholder_unit("blue", p)
                      for p in range(7, 13)]
        return units_red, units_blue

    # --- остальное без изменений ---
    def preview(self):
        units_red, units_blue = self._collect_units_with_placeholders()
        if units_red is None:
            return
        msg = "UNITS_RED = " + pformat(units_red, width=120, compact=False, sort_dicts=False) \
              + "\n\nUNITS_BLUE = " + pformat(units_blue, width=120, compact=False, sort_dicts=False)
        try:
            self.master.clipboard_clear()
            self.master.clipboard_append(msg)
            self.master.update()
        except Exception as e:
            messagebox.showwarning("Буфер обмена", f"Не удалось скопировать в буфер обмена:\n{e}")

        top = Toplevel(self.master)
        top.title("Предпросмотр (скопировано в буфер обмена)")
        from tkinter.scrolledtext import ScrolledText
        st = ScrolledText(top, width=140, height=44)
        st.pack(fill="both", expand=True)
        st.insert("1.0", msg)
        st.configure(state="disabled")
        Label(top, text="Содержимое предпросмотра скопировано в буфер обмена.").pack(pady=(4, 0))
        Button(top, text="Закрыть", command=top.destroy).pack(pady=6)

    def save_to_file(self):
        units_red, units_blue = self._collect_units_compact()
        if units_red is None:
            return
        py_path = os.path.join(os.getcwd(), "1workingbattle.py")
        try:
            write_units_to_file(py_path, units_red, units_blue)
        except Exception as e:
            messagebox.showerror("Ошибка записи", f"Не удалось записать в {py_path}\n{e}")
            return
        messagebox.showinfo("Готово", f"UNITS_RED/UNITS_BLUE записаны в {py_path} (кастомный блок в конце файла).")

    def save_and_run(self):
        self.save_to_file()
        py_path = os.path.join(os.getcwd(), "1workingbattle.py")
        if os.path.exists(py_path):
            run_battle(py_path)

    def clear_all(self):
        for v in self._all_vars:
            v.set(NO_SELECTION)

# ========================== START GUI ===========================
if __name__ == "__main__":
    try:
        DATA  # noqa: just to check presence
    except NameError:
        raise SystemExit("Ошибка: переменная DATA не найдена. Импортируй/объяви DATA перед запуском GUI.")

    root = Tk()
    app = BattleSelectorGUI(root, DATA)
    root.mainloop()
